import{bV as n,aZ as a,aL as d,u as c,G as s,I as i,bJ as t}from"./chunks/framework.BfzMay2U.js";const g=JSON.parse('{"title":"redis持久化机制以及缓存过期和淘汰策略","description":"","frontmatter":{"title":"redis持久化机制以及缓存过期和淘汰策略","date":"2023-01-04T22:03:10.000Z","categories":["Redis"],"tags":["redis"]},"headers":[],"relativePath":"views/redis/persistence-and-lrfu.md","filePath":"views/redis/persistence-and-lrfu.md"}'),r={name:"views/redis/persistence-and-lrfu.md"};function p(h,e,k,u,b,m){const l=a("MermaidChart"),o=a("ClientOnly");return d(),c("div",null,[e[0]||(e[0]=s(`<h1 id="redis-持久化机制以及缓存过期和淘汰策略" tabindex="-1">redis 持久化机制以及缓存过期和淘汰策略 <a class="header-anchor" href="#redis-持久化机制以及缓存过期和淘汰策略" aria-label="Permalink to &quot;redis 持久化机制以及缓存过期和淘汰策略&quot;">​</a></h1><h2 id="持久化" tabindex="-1">持久化 <a class="header-anchor" href="#持久化" aria-label="Permalink to &quot;持久化&quot;">​</a></h2><h3 id="模式" tabindex="-1">模式 <a class="header-anchor" href="#模式" aria-label="Permalink to &quot;模式&quot;">​</a></h3><ul><li><code>rdb</code>：生成某一时刻的快照，然后保存到二进制文件中</li><li><code>aof</code>：记录每一条写命令，追加到文件中，打开可以看到具体的操作记录</li><li>混合模式: 上面 2 种方式的结合</li></ul><h3 id="触发方式" tabindex="-1">触发方式 <a class="header-anchor" href="#触发方式" aria-label="Permalink to &quot;触发方式&quot;">​</a></h3><ul><li><p><code>save</code>：会让<code>redis</code>处于阻塞状态，直到<code>rdb</code>持久化完成，线上环境需要谨慎使用</p></li><li><p><code>bgsave</code>，它会<code>fork</code>出一个子进程，用来执行持久化，主进程继续响应客户端请求，有短暂的阻塞</p></li><li><p>自动触发：在<code>m</code>秒内，有<code>n</code>个<code>key</code>发生改变，就会触发；执行命令最终执行的是<code>bgsave</code></p><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># after 900 sec (15 min) if at leaset 1 key changed</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">save 900 1</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># after 300 sec (5 min) if at least 10 keys changed</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">save 300 10</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># after 60 sec (1 min) if at least 10000 keys changed</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">save 60 10000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></li></ul><h3 id="rdb-优缺点" tabindex="-1">rdb 优缺点 <a class="header-anchor" href="#rdb-优缺点" aria-label="Permalink to &quot;rdb 优缺点&quot;">​</a></h3><blockquote><p>优点</p></blockquote><ul><li>容灾性好，方便备份</li><li>性能最大化，<code>fork</code>出一个子进程来操作，对主进程没有影响</li><li>数据比较多的时候，相对于<code>aof</code>启动效率比较高</li></ul><blockquote><p>缺点</p></blockquote><ul><li>会造成数据丢失，因为它是过一段时间触发一次持久化，假如中间发生点故障，会导致这个时间段的数据丢失</li></ul><h3 id="aof-的优缺点" tabindex="-1">aof 的优缺点 <a class="header-anchor" href="#aof-的优缺点" aria-label="Permalink to &quot;aof 的优缺点&quot;">​</a></h3>`,12)),i(o,null,{default:t(()=>[i(l,{code:"graph%20TD%0A%20%20%20%E5%91%BD%E4%BB%A4%20--%3E%20AOF%E7%BC%93%E5%86%B2%E5%8C%BA%20--%20%E5%90%8C%E6%AD%A5%E7%AD%96%E7%95%A5%20--%3E%20AOF%E6%96%87%E4%BB%B6%20--%20%E9%87%8D%E5%86%99%E7%AD%96%E7%95%A5%20--%3E%20AOF%E6%96%87%E4%BB%B6%0A",showToolbar:"1"})]),_:1}),e[1]||(e[1]=s(`<blockquote><p>同步策略</p></blockquote><ul><li><code>everysec</code>：每秒同步一次</li><li><code>always</code>：每次操作之后都要同步一次</li><li><code>no</code>：由操作系统调度进行同步</li></ul><blockquote><p>重写策略</p></blockquote><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aaa</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 追加一次aof中</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bbb</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 追加一次到aof中</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ccc</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 再次追加</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 最后获取</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> name</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 得到 ccc 最后一次命令</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>那么中间保存的<code>aaa</code>和<code>bbb</code>就没有意义了，<code>aof</code>在恢复的时候会一条条命令去执行，这样没有意义的占用的空间，所以<code>redis</code>就提供了一个重写的策略，当<code>aof</code>文件达到了一定大小的时候，就会来执行，把中间的这些过程删掉，只留下最后一条命令，这样<code>aof</code>文件就会小很多。</p><ul><li>手动触发：执行<code>bgrewriteaof</code>命令</li><li>自动触发</li></ul><p><code>auto-aof-rewrite-percentage</code>：当前<code>AOF</code>文件大小和最后一次重写的大小之间的比率等于或者等于指定的增长百分比，如 100 代表当前的<code>AOF</code>文件是上次重写的 2 倍时候才重写</p><p><code>auto-aof-rewrite-min-size</code>：当<code>AOF</code>文件大小大于该值的时候才可能重写</p><blockquote><p>优点</p></blockquote><ul><li>数据安全，不会造成数据丢失</li></ul><blockquote><p>缺点</p></blockquote><ul><li>比<code>rdb</code>重启效率低；运行效率比<code>rdb</code>低，它是一条条保存的，恢复也是一条条执行的。</li></ul><h2 id="过期键删除策略" tabindex="-1">过期键删除策略 <a class="header-anchor" href="#过期键删除策略" aria-label="Permalink to &quot;过期键删除策略&quot;">​</a></h2><p><code>redis</code>设置<code>key</code>时，都会设置一个过期时间，那么当过期时间到了，<code>redis</code>就会同时使用惰性过期和定期过期。</p><h3 id="惰性过期" tabindex="-1">惰性过期 <a class="header-anchor" href="#惰性过期" aria-label="Permalink to &quot;惰性过期&quot;">​</a></h3><p>只有当这个<code>key</code>被访问时，才会判断是否过期，过期则清理掉。它可以节省<code>cpu</code>的资源，但是会浪费内存的资源。会出现大量过期的<code>key</code>没有被访问过，从而不会被清除，导致内容占用越来越大。</p><h3 id="定期过期" tabindex="-1">定期过期 <a class="header-anchor" href="#定期过期" aria-label="Permalink to &quot;定期过期&quot;">​</a></h3><p>每间隔一段时间，<strong>扫描一定数量的</strong>设置了过期时间的<code>key</code>，假如过期了则删除。</p><p><code>redis</code>默认每秒进行 10 次过期扫描</p><ol><li>从过期字典中随机 20 个<code>key</code></li><li>删除这 20 个<code>key</code>中已经过期的</li><li>如果超过 25%的<code>key</code>过期，则重复第一步；同时，为了保证业务不受影响，<code>redis</code>还设置了扫描的时间上限，默认不会超过 25<code>ms</code></li></ol><h2 id="内存淘汰策略" tabindex="-1">内存淘汰策略 <a class="header-anchor" href="#内存淘汰策略" aria-label="Permalink to &quot;内存淘汰策略&quot;">​</a></h2><p>假如内存不足时，<code>redis</code>会根据设置的淘汰策略，删除一些不常用的数据，保证<code>redis</code>的正常使用。</p><p>配置项：</p><ul><li><code>noeviction</code>：当内存使用超过配置的时候会返回错误，不会驱逐任何键</li><li><code>allkeys-lru</code>：加入键的时候，如果过限，首先通过<code>LRU</code>算法驱逐最久没有使用的键</li><li><code>volatile-lru</code>：加入键的时候如果过限，首先从设置了过期的键集合中驱逐最久没有使用的键</li><li><code>allkeys-random</code>：加入键的时候如果过限，从所有<code>key</code>随机删除</li><li><code>volatile-random</code>：加入键的时候如果过限，从过期键的集合中随机驱逐</li><li><code>volatile-ttl</code>：从配置了过期时间的键中驱逐马上就要过期的键</li><li><code>volatile-lfu</code>：从所有配置了过期时间的键中驱逐使用频率最少的键</li><li><code>allkeys-lfu</code>：从所有键中驱逐使用频率最少的键</li></ul><h3 id="lru-最近最少使用" tabindex="-1">LRU 最近最少使用 <a class="header-anchor" href="#lru-最近最少使用" aria-label="Permalink to &quot;LRU 最近最少使用&quot;">​</a></h3><p>根据最近被使用的时间，离当前最远的数据优先被淘汰；</p><p>新加入和访问的键会放在队尾，未被使用的和即将淘汰的则会放在队头。</p><p>当有了很多个<code>key</code>的使用时间在头时，就需要去考虑使用次数的频率来判断谁应该优先淘汰，就产生了<code>LFU</code></p><h3 id="lfu-最不经常使用" tabindex="-1">LFU 最不经常使用 <a class="header-anchor" href="#lfu-最不经常使用" aria-label="Permalink to &quot;LFU 最不经常使用&quot;">​</a></h3><p>最终还是要根据实际业务去选择哪个算法以及什么配置。</p>`,30))])}const y=n(r,[["render",p]]);export{g as __pageData,y as default};
